const nvdData = $('Fetch NVD CVEs').first().json;
const cisaData = $('Fetch CISA KEV').first().json;

const items = [];

// Process top 3 NVD CVEs
const cves = (nvdData.vulnerabilities || []).slice(0, 3);
for (const entry of cves) {
  const cve = entry.cve;
  const desc = (cve.descriptions || []).find(d => d.lang === 'en');
  if (!desc) continue;
  const cvssScore = cve.metrics?.cvssMetricV31?.[0]?.cvssData?.baseScore
    || cve.metrics?.cvssMetricV30?.[0]?.cvssData?.baseScore
    || 0;
  items.push({
    title: cve.id,
    content: desc.value,
    category: 'vulnerability',
    source_url: `https://nvd.nist.gov/vuln/detail/${cve.id}`,
    cvss: cvssScore
  });
}

// Process top 2 CISA KEVs (most recent)
const kevs = (cisaData.vulnerabilities || []).slice(-2).reverse();
for (const kev of kevs) {
  items.push({
    title: `${kev.cveID}: ${kev.vulnerabilityName}`,
    content: `${kev.shortDescription} Affected product: ${kev.product} by ${kev.vendorProject}. Required action: ${kev.requiredAction}`,
    category: 'exploited-in-wild',
    source_url: `https://nvd.nist.gov/vuln/detail/${kev.cveID}`,
    cvss: 0
  });
}

return items.map(item => ({ json: item }));

const summarized = $input.all();

const items = summarized.map(item => ({
  title: item.json.title,
  summary: item.json.summary,
  risk_level: item.json.risk_level,
  category: item.json.category,
  source_url: item.json.source_url || '',
  updated_at: new Date().toISOString()
}));

const digest = {
  updated_at: new Date().toISOString(),
  items: items
};

const content = btoa(unescape(encodeURIComponent(JSON.stringify(digest, null, 2))));

return [{ json: { digest, content } }];
